import{_ as s,c as a,e as t,o as e}from"./app-C6IMVStD.js";const p="/assets/images/authn_vs_authz.jpg",o={};function l(c,n){return e(),a("div",null,[...n[0]||(n[0]=[t('<h1 id="kratos微服务框架下的认证和鉴权" tabindex="-1"><a class="header-anchor" href="#kratos微服务框架下的认证和鉴权"><span>Kratos微服务框架下的认证和鉴权</span></a></h1><p>从单体应用迁移到微服务架构，虽能收获松耦合、可扩展等诸多优势，但也引入了新的安全挑战。微服务通过开放 API 实现服务间通信，与单体应用相比：​</p><ul><li>攻击面显著扩大：每个独立服务都需单独保障安全性，风险点呈指数级增加​</li><li>通信安全性要求更高：API 调用不仅要验证身份，还需保障传输安全与可用性​</li></ul><p>因此，微服务架构需要一套与单体应用截然不同的安全解决方案，核心聚焦于认证（Authentication） 与鉴权（Authorization） 两大核心能力。</p><h2 id="一、认证与鉴权的核心区别​" tabindex="-1"><a class="header-anchor" href="#一、认证与鉴权的核心区别​"><span>一、认证与鉴权的核心区别​</span></a></h2><p><img src="'+p+`" alt="认证和授权的区别"></p><h3 id="身份认证-authentication-​" tabindex="-1"><a class="header-anchor" href="#身份认证-authentication-​"><span>身份认证（Authentication）​</span></a></h3><ul><li>核心问题：<strong>&quot;你是谁？&quot;​</strong></li><li>核心目标：验证用户身份的合法性，确认请求者是否为其声称的身份​</li><li>典型场景：用户登录时提交用户名密码、手机号验证码等凭证​</li></ul><h3 id="授权-authorization-​" tabindex="-1"><a class="header-anchor" href="#授权-authorization-​"><span>授权（Authorization）​</span></a></h3><ul><li>核心问题：<strong>&quot;你有什么权限？&quot;​</strong></li><li>核心目标：在身份认证通过后，判断用户是否有权访问特定资源或执行特定操作​</li><li>典型场景：普通用户能否修改他人数据、管理员能否删除系统配置</li></ul><h2 id="二、微服务下的认证与鉴权策略选型​" tabindex="-1"><a class="header-anchor" href="#二、微服务下的认证与鉴权策略选型​"><span>二、微服务下的认证与鉴权策略选型​</span></a></h2><table><thead><tr><th>架构模式</th><th>策略类型</th><th>核心特点</th></tr></thead><tbody><tr><td>无 API 网关</td><td>1.1 服务各自认证鉴权</td><td>耦合度高、重复开发、维护成本高</td></tr><tr><td></td><td>1.2 独立认证授权服务</td><td>认证鉴权集中化，但未解决 API 层统一拦截问题</td></tr><tr><td>有 API 网关</td><td>2.1 网关认证 + 服务鉴权</td><td>认证统一化，鉴权分散导致权限管理混乱</td></tr><tr><td></td><td>2.2 网关统一认证鉴权</td><td>性能高效，但网关压力过大，灵活性不足</td></tr><tr><td></td><td>2.3 独立认证服务 + 网关鉴权</td><td>认证与鉴权解耦，兼顾性能与灵活性（推荐）</td></tr></tbody></table><p>推荐策略：2.3 独立认证服务 + 网关鉴权​</p><p>选择该策略的核心原因：​</p><ul><li><strong>频率差异适配</strong>：认证（如登录）是低频操作，独立部署可专注处理复杂身份校验；鉴权（如 API 调用）是高频操作，在网关层处理可降低服务响应延迟​</li><li><strong>复杂度分离</strong>：认证涉及用户凭证校验、令牌生成等特异性逻辑，独立服务便于定制化；鉴权规则（如 RBAC）具有通用性，网关层统一实现可减少重复开发</li></ul><h2 id="三、有状态-vs-无状态身份验证​" tabindex="-1"><a class="header-anchor" href="#三、有状态-vs-无状态身份验证​"><span>三、有状态 vs 无状态身份验证​</span></a></h2><p>服务端识别客户端身份的两种核心模式，其本质区别在于是否存储客户端状态信息：​</p><h3 id="有状态认证-cookie-session-模式-​" tabindex="-1"><a class="header-anchor" href="#有状态认证-cookie-session-模式-​"><span>有状态认证（Cookie-Session 模式）​</span></a></h3><ul><li>工作流程：客户端首次登录后，服务端生成 Session 并存储用户信息，返回 SessionID（通常通过 Cookie 传递）；后续请求客户端携带 SessionID，服务端查询 Session 确认身份​</li><li>优缺点：实现简单，但服务端需维护 Session 状态，扩展性差，不适合分布式部署​</li></ul><h3 id="无状态认证-token-模式-​" tabindex="-1"><a class="header-anchor" href="#无状态认证-token-模式-​"><span>无状态认证（Token 模式）​</span></a></h3><ul><li>工作流程：客户端登录后，服务端验证身份并生成加密 Token（如 JWT）返回；后续请求客户端携带 Token，服务端通过解密 Token 直接获取用户信息，无需存储状态​</li><li>优缺点：服务端无状态，扩展性强，适合微服务架构；需解决 Token 安全传输与失效管理问题​</li></ul><h2 id="四、技术实现方案​" tabindex="-1"><a class="header-anchor" href="#四、技术实现方案​"><span>四、技术实现方案​</span></a></h2><p>结合 Kratos 框架特性，最终技术选型如下：​</p><ul><li>微服务框架：<a href="https://go-kratos.dev/" target="_blank" rel="noopener noreferrer">Kratos</a>（B 站开源，轻量、高可用、原生支持微服务生态）​</li><li>认证机制：<a href="https://jwt.io/" target="_blank" rel="noopener noreferrer">JWT</a>（无状态 Token，适合分布式环境）​</li><li>鉴权框架：<a href="https://casbin.org/" target="_blank" rel="noopener noreferrer">Casbin</a>（支持多权限模型，通用性强）</li></ul><h3 id="_4-1-jwt-无状态认证的核心实现​" tabindex="-1"><a class="header-anchor" href="#_4-1-jwt-无状态认证的核心实现​"><span>4.1 JWT：无状态认证的核心实现​</span></a></h3><h4 id="什么是-jwt-​" tabindex="-1"><a class="header-anchor" href="#什么是-jwt-​"><span>什么是 JWT？​</span></a></h4><p>JSON Web Token（JWT）是基于 RFC 7519 标准的轻量级令牌，用于在分布式系统中安全传递用户身份信息。其结构由三部分组成：​</p><ul><li>Header（头部）：指定令牌类型与加密算法​</li><li>Payload（负载）：存储用户 ID、权限等核心信息（不建议存储敏感数据）​</li><li>Signature（签名）：通过密钥对前两部分加密，防止篡改​</li></ul><h4 id="jwt-使用注意事项​" tabindex="-1"><a class="header-anchor" href="#jwt-使用注意事项​"><span>JWT 使用注意事项​</span></a></h4><ol><li>默认不加密，敏感数据禁止存入 Payload​</li><li>令牌有效期应设置较短（如 1 小时），通过刷新令牌机制延长会话​</li><li>必须通过 HTTPS 传输，防止令牌被窃取​</li><li>服务端无法主动废止已签发的令牌，需通过黑名单机制处理特殊场景（如用户登出）​</li><li>可用于身份认证与数据交换，减少数据库查询次数</li></ol><h3 id="_4-2-casbin-通用鉴权框架​" tabindex="-1"><a class="header-anchor" href="#_4-2-casbin-通用鉴权框架​"><span>4.2 Casbin：通用鉴权框架​</span></a></h3><h4 id="什么是-casbin-​" tabindex="-1"><a class="header-anchor" href="#什么是-casbin-​"><span>什么是 Casbin？​</span></a></h4><p>Casbin 是一个开源访问控制框架，核心优势在于 <strong>将权限模型与业务逻辑解耦</strong>，支持 ACL、RBAC、ABAC 等多种权限模型，提供跨语言支持与灵活的规则配置。​</p><h4 id="casbin-的核心能力​" tabindex="-1"><a class="header-anchor" href="#casbin-的核心能力​"><span>Casbin 的核心能力​</span></a></h4><ul><li>✅ 支持自定义请求格式（默认：<code>{主体(subject), 资源(object), 操作(action)}</code>）​</li><li>✅ 支持 RBAC 多层角色继承（用户与资源均可拥有角色）​</li><li>✅ 内置超级用户机制与路径匹配运算符（如<code>keyMatch</code>匹配<code>/foo/*</code>路径）​</li><li>❌ 不负责身份认证（需与 JWT 等认证机制配合）​</li><li>❌ 不管理用户 / 角色列表（仅存储用户 - 角色映射关系）</li></ul><h3 id="_4-3-kratos-框架下的落地实现​" tabindex="-1"><a class="header-anchor" href="#_4-3-kratos-框架下的落地实现​"><span>4.3 Kratos 框架下的落地实现​</span></a></h3><p>Kratos 通过中间件机制实现认证与鉴权的统一拦截，以下是完整实现步骤：</p><h4 id="第一步-定义-securityuser-结构体​" tabindex="-1"><a class="header-anchor" href="#第一步-定义-securityuser-结构体​"><span>第一步：定义 SecurityUser 结构体​</span></a></h4><p>用于封装 JWT 令牌信息与 Casbin 鉴权所需的核心数据（主体、资源、操作）：</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">const</span> <span class="token punctuation">(</span></span>
<span class="line">    ClaimAuthorityId <span class="token operator">=</span> <span class="token string">&quot;authorityId&quot;</span> <span class="token comment">// JWT负载中存储权限ID的字段</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// SecurityUser 实现认证鉴权所需的用户信息接口</span></span>
<span class="line"><span class="token keyword">type</span> SecurityUser <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Path        <span class="token builtin">string</span> <span class="token comment">// 访问的资源路径（对应API操作名）</span></span>
<span class="line">    Method      <span class="token builtin">string</span> <span class="token comment">// 请求方法（*表示所有方法）</span></span>
<span class="line">    AuthorityId <span class="token builtin">string</span> <span class="token comment">// 用户权限ID（如admin/moderator）</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// NewSecurityUser 创建SecurityUser实例</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewSecurityUser</span><span class="token punctuation">(</span><span class="token punctuation">)</span> authzM<span class="token punctuation">.</span>SecurityUser <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>SecurityUser<span class="token punctuation">{</span><span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// ParseFromContext 从上下文解析JWT信息与请求信息</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>su <span class="token operator">*</span>SecurityUser<span class="token punctuation">)</span> <span class="token function">ParseFromContext</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 从上下文获取JWT负载</span></span>
<span class="line">    <span class="token keyword">if</span> claims<span class="token punctuation">,</span> ok <span class="token operator">:=</span> jwt<span class="token punctuation">.</span><span class="token function">FromContext</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span><span class="token punctuation">;</span> ok <span class="token punctuation">{</span></span>
<span class="line">        su<span class="token punctuation">.</span>AuthorityId <span class="token operator">=</span> claims<span class="token punctuation">.</span><span class="token punctuation">(</span>jwtV4<span class="token punctuation">.</span>MapClaims<span class="token punctuation">)</span><span class="token punctuation">[</span>ClaimAuthorityId<span class="token punctuation">]</span><span class="token punctuation">.</span><span class="token punctuation">(</span><span class="token builtin">string</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> errors<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;jwt claim missing&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 从上下文获取请求操作信息</span></span>
<span class="line">    <span class="token keyword">if</span> header<span class="token punctuation">,</span> ok <span class="token operator">:=</span> transport<span class="token punctuation">.</span><span class="token function">FromServerContext</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span><span class="token punctuation">;</span> ok <span class="token punctuation">{</span></span>
<span class="line">        su<span class="token punctuation">.</span>Path <span class="token operator">=</span> header<span class="token punctuation">.</span><span class="token function">Operation</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token comment">// Kratos中API操作名（如/admin.v1.AdminService/Login）</span></span>
<span class="line">        su<span class="token punctuation">.</span>Method <span class="token operator">=</span> <span class="token string">&quot;*&quot;</span></span>
<span class="line">    <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> errors<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;request header missing&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    </span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token comment">// 以下方法实现authzM.SecurityUser接口，提供Casbin所需的三元组信息</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>su <span class="token operator">*</span>SecurityUser<span class="token punctuation">)</span> <span class="token function">GetSubject</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span> <span class="token punctuation">{</span> <span class="token keyword">return</span> su<span class="token punctuation">.</span>AuthorityId <span class="token punctuation">}</span> <span class="token comment">// 主体（用户权限ID）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>su <span class="token operator">*</span>SecurityUser<span class="token punctuation">)</span> <span class="token function">GetObject</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span>  <span class="token punctuation">{</span> <span class="token keyword">return</span> su<span class="token punctuation">.</span>Path <span class="token punctuation">}</span>        <span class="token comment">// 资源（API操作名）</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>su <span class="token operator">*</span>SecurityUser<span class="token punctuation">)</span> <span class="token function">GetAction</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token builtin">string</span>  <span class="token punctuation">{</span> <span class="token keyword">return</span> su<span class="token punctuation">.</span>Method <span class="token punctuation">}</span>      <span class="token comment">// 操作（请求方法）</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="第二步-实现-jwt-认证中间件​" tabindex="-1"><a class="header-anchor" href="#第二步-实现-jwt-认证中间件​"><span>第二步：实现 JWT 认证中间件​</span></a></h4><h5 id="_1-创建白名单匹配器-免认证接口-​" tabindex="-1"><a class="header-anchor" href="#_1-创建白名单匹配器-免认证接口-​"><span>1. 创建白名单匹配器（免认证接口）​</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// NewWhiteListMatcher 定义无需认证鉴权的API操作名</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewWhiteListMatcher</span><span class="token punctuation">(</span><span class="token punctuation">)</span> selector<span class="token punctuation">.</span>MatchFunc <span class="token punctuation">{</span></span>
<span class="line">    whiteList <span class="token operator">:=</span> <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span><span class="token builtin">bool</span><span class="token punctuation">{</span></span>
<span class="line">        <span class="token string">&quot;/admin.v1.AdminService/Login&quot;</span><span class="token punctuation">:</span> <span class="token boolean">true</span><span class="token punctuation">,</span> <span class="token comment">// 登录接口免认证</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token comment">// 返回匹配函数：白名单内的操作返回false（跳过中间件）</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token keyword">func</span><span class="token punctuation">(</span>ctx context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> operation <span class="token builtin">string</span><span class="token punctuation">)</span> <span class="token builtin">bool</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token operator">!</span>whiteList<span class="token punctuation">[</span>operation<span class="token punctuation">]</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-构建-jwt-中间件​" tabindex="-1"><a class="header-anchor" href="#_2-构建-jwt-中间件​"><span>2. 构建 JWT 中间件​</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// NewAuthMiddleware 创建JWT认证中间件</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewAuthMiddleware</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">,</span> apiKey <span class="token builtin">string</span><span class="token punctuation">)</span> http<span class="token punctuation">.</span>ServerOption <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> http<span class="token punctuation">.</span><span class="token function">Middleware</span><span class="token punctuation">(</span></span>
<span class="line">        recovery<span class="token punctuation">.</span><span class="token function">Recovery</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>       <span class="token comment">// 异常恢复中间件</span></span>
<span class="line">        tracing<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span>          <span class="token comment">// 链路追踪中间件</span></span>
<span class="line">        logging<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span>logger<span class="token punctuation">)</span><span class="token punctuation">,</span>    <span class="token comment">// 日志中间件</span></span>
<span class="line">        <span class="token comment">// 选择性应用JWT中间件（白名单接口跳过）</span></span>
<span class="line">        selector<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">            jwt<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">                <span class="token comment">// JWT密钥验证函数</span></span>
<span class="line">                <span class="token keyword">func</span><span class="token punctuation">(</span>token <span class="token operator">*</span>jwtV4<span class="token punctuation">.</span>Token<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token keyword">interface</span><span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">                    <span class="token keyword">return</span> <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>apiKey<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line">                <span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">                jwt<span class="token punctuation">.</span><span class="token function">WithSigningMethod</span><span class="token punctuation">(</span>jwtV4<span class="token punctuation">.</span>SigningMethodHS256<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 指定HS256加密算法</span></span>
<span class="line">            <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Match</span><span class="token punctuation">(</span><span class="token function">NewWhiteListMatcher</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-注册中间件​" tabindex="-1"><a class="header-anchor" href="#_3-注册中间件​"><span>3. 注册中间件​</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// 服务启动选项配置</span></span>
<span class="line"><span class="token keyword">var</span> opts <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>http<span class="token punctuation">.</span>ServerOption<span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">NewAuthMiddleware</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> ac<span class="token punctuation">.</span>ApiKey<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 注册JWT认证中间件</span></span>
<span class="line">    <span class="token comment">// CORS跨域配置</span></span>
<span class="line">    http<span class="token punctuation">.</span><span class="token function">Filter</span><span class="token punctuation">(</span>handlers<span class="token punctuation">.</span><span class="token function">CORS</span><span class="token punctuation">(</span></span>
<span class="line">        handlers<span class="token punctuation">.</span><span class="token function">AllowedHeaders</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span><span class="token string">&quot;X-Requested-With&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Content-Type&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;Authorization&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        handlers<span class="token punctuation">.</span><span class="token function">AllowedMethods</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span><span class="token string">&quot;GET&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;POST&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;PUT&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;DELETE&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;HEAD&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;OPTIONS&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        handlers<span class="token punctuation">.</span><span class="token function">AllowedOrigins</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span><span class="token punctuation">{</span><span class="token string">&quot;*&quot;</span><span class="token punctuation">}</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_4-前端-token-传递方式​" tabindex="-1"><a class="header-anchor" href="#_4-前端-token-传递方式​"><span>4. 前端 Token 传递方式​</span></a></h5><p>前端需在 HTTP 请求头中携带 JWT 令牌，格式为<code>Bearer {Token}</code>：​</p><div class="language-typescript line-numbers-mode" data-highlighter="prismjs" data-ext="ts"><pre><code><span class="line"><span class="token comment">// 生成认证请求头</span></span>
<span class="line"><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token keyword">function</span> <span class="token function">authHeader</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">  <span class="token keyword">const</span> userStr <span class="token operator">=</span> localStorage<span class="token punctuation">.</span><span class="token function">getItem</span><span class="token punctuation">(</span><span class="token string">&quot;user&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token keyword">let</span> user <span class="token operator">=</span> userStr <span class="token operator">?</span> <span class="token constant">JSON</span><span class="token punctuation">.</span><span class="token function">parse</span><span class="token punctuation">(</span>userStr<span class="token punctuation">)</span> <span class="token operator">:</span> <span class="token keyword">null</span><span class="token punctuation">;</span></span>
<span class="line">  </span>
<span class="line">  <span class="token keyword">if</span> <span class="token punctuation">(</span>user <span class="token operator">&amp;&amp;</span> user<span class="token punctuation">.</span>token<span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">{</span> Authorization<span class="token operator">:</span> <span class="token template-string"><span class="token template-punctuation string">\`</span><span class="token string">Bearer </span><span class="token interpolation"><span class="token interpolation-punctuation punctuation">\${</span>user<span class="token punctuation">.</span>token<span class="token interpolation-punctuation punctuation">}</span></span><span class="token template-punctuation string">\`</span></span> <span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span> <span class="token keyword">else</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token punctuation">{</span><span class="token punctuation">}</span><span class="token punctuation">;</span></span>
<span class="line">  <span class="token punctuation">}</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="第三步-实现-casbin-鉴权中间件​" tabindex="-1"><a class="header-anchor" href="#第三步-实现-casbin-鉴权中间件​"><span>第三步：实现 Casbin 鉴权中间件​</span></a></h4><h5 id="_1-配置-casbin-模型与策略​" tabindex="-1"><a class="header-anchor" href="#_1-配置-casbin-模型与策略​"><span>1. 配置 Casbin 模型与策略​</span></a></h5><h6 id="模型文件-authz-model-conf-定义-rbac-权限模型" tabindex="-1"><a class="header-anchor" href="#模型文件-authz-model-conf-定义-rbac-权限模型"><span>模型文件（authz_model.conf）：定义 RBAC 权限模型</span></a></h6><div class="language-ini line-numbers-mode" data-highlighter="prismjs" data-ext="ini"><pre><code><span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">request_definition</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">r</span> <span class="token punctuation">=</span> <span class="token value attr-value">sub, obj, act</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">policy_definition</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">p</span> <span class="token punctuation">=</span> <span class="token value attr-value">sub, obj, act</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">role_definition</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">g</span> <span class="token punctuation">=</span> <span class="token value attr-value">_, _</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">policy_effect</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">e</span> <span class="token punctuation">=</span> <span class="token value attr-value">some(where (p.eft == allow))</span></span>
<span class="line"></span>
<span class="line"><span class="token section"><span class="token punctuation">[</span><span class="token section-name selector">matchers</span><span class="token punctuation">]</span></span></span>
<span class="line"><span class="token key attr-name">m</span> <span class="token punctuation">=</span> <span class="token value attr-value">g(r.sub, p.sub) &amp;&amp; keyMatch(r.obj, p.obj) &amp;&amp; r.act == p.act</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h6 id="策略文件-authz-policy-csv-定义具体权限规则​" tabindex="-1"><a class="header-anchor" href="#策略文件-authz-policy-csv-定义具体权限规则​"><span>策略文件（authz_policy.csv）：定义具体权限规则​</span></a></h6><div class="language-csv line-numbers-mode" data-highlighter="prismjs" data-ext="csv"><pre><code><span class="line"><span class="token value">p</span><span class="token punctuation">,</span><span class="token value"> ROLE_ADMIN</span><span class="token punctuation">,</span><span class="token value"> /admin.v1.AdminService/*</span><span class="token punctuation">,</span><span class="token value"> *</span></span>
<span class="line"><span class="token value">p</span><span class="token punctuation">,</span><span class="token value"> ROLE_MODERATOR</span><span class="token punctuation">,</span><span class="token value"> /admin.v1.AdminService/ListUsers</span><span class="token punctuation">,</span><span class="token value"> *</span></span>
<span class="line"><span class="token value">g</span><span class="token punctuation">,</span><span class="token value"> admin</span><span class="token punctuation">,</span><span class="token value"> ROLE_ADMIN</span></span>
<span class="line"><span class="token value">g</span><span class="token punctuation">,</span><span class="token value"> moderator</span><span class="token punctuation">,</span><span class="token value"> ROLE_MODERATOR</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_2-构建-casbin-中间件​" tabindex="-1"><a class="header-anchor" href="#_2-构建-casbin-中间件​"><span>2. 构建 Casbin 中间件​</span></a></h5><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token comment">// NewAuthzMiddleware 创建Casbin鉴权中间件</span></span>
<span class="line"><span class="token keyword">func</span> <span class="token function">NewAuthzMiddleware</span><span class="token punctuation">(</span>logger log<span class="token punctuation">.</span>Logger<span class="token punctuation">)</span> http<span class="token punctuation">.</span>ServerOption <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 从文件加载Casbin模型与策略</span></span>
<span class="line">    model<span class="token punctuation">,</span> <span class="token boolean">_</span> <span class="token operator">:=</span> model<span class="token punctuation">.</span><span class="token function">NewModelFromFile</span><span class="token punctuation">(</span><span class="token string">&quot;../../configs/authz/authz_model.conf&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    adapter <span class="token operator">:=</span> fileAdapter<span class="token punctuation">.</span><span class="token function">NewAdapter</span><span class="token punctuation">(</span><span class="token string">&quot;../../configs/authz/authz_policy.csv&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    </span>
<span class="line">    <span class="token keyword">return</span> http<span class="token punctuation">.</span><span class="token function">Middleware</span><span class="token punctuation">(</span></span>
<span class="line">        recovery<span class="token punctuation">.</span><span class="token function">Recovery</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        tracing<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        logging<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span>logger<span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token comment">// 选择性应用鉴权中间件（白名单接口跳过）</span></span>
<span class="line">        selector<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">            casbinM<span class="token punctuation">.</span><span class="token function">Server</span><span class="token punctuation">(</span></span>
<span class="line">                casbinM<span class="token punctuation">.</span><span class="token function">WithCasbinModel</span><span class="token punctuation">(</span>model<span class="token punctuation">)</span><span class="token punctuation">,</span>          <span class="token comment">// 注入Casbin模型</span></span>
<span class="line">                casbinM<span class="token punctuation">.</span><span class="token function">WithCasbinPolicy</span><span class="token punctuation">(</span>adapter<span class="token punctuation">)</span><span class="token punctuation">,</span>      <span class="token comment">// 注入权限策略</span></span>
<span class="line">                casbinM<span class="token punctuation">.</span><span class="token function">WithSecurityUserCreator</span><span class="token punctuation">(</span>NewSecurityUser<span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token comment">// 注入用户信息构造器</span></span>
<span class="line">            <span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">        <span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Match</span><span class="token punctuation">(</span><span class="token function">NewWhiteListMatcher</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span><span class="token punctuation">.</span><span class="token function">Build</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h5 id="_3-注册鉴权中间件​" tabindex="-1"><a class="header-anchor" href="#_3-注册鉴权中间件​"><span>3. 注册鉴权中间件​</span></a></h5><p>在 HTTP 服务选项中添加 Casbin 中间件（需在 JWT 中间件之后）：​</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">var</span> opts <span class="token operator">=</span> <span class="token punctuation">[</span><span class="token punctuation">]</span>http<span class="token punctuation">.</span>ServerOption<span class="token punctuation">{</span></span>
<span class="line">    <span class="token function">NewAuthMiddleware</span><span class="token punctuation">(</span>logger<span class="token punctuation">,</span> ac<span class="token punctuation">.</span>ApiKey<span class="token punctuation">)</span><span class="token punctuation">,</span>   <span class="token comment">// 先认证</span></span>
<span class="line">    <span class="token function">NewAuthzMiddleware</span><span class="token punctuation">(</span>logger<span class="token punctuation">)</span><span class="token punctuation">,</span>             <span class="token comment">// 后鉴权</span></span>
<span class="line">    <span class="token comment">// ...其他中间件</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h4 id="第四步-实现登录接口-生成-jwt-令牌-​" tabindex="-1"><a class="header-anchor" href="#第四步-实现登录接口-生成-jwt-令牌-​"><span>第四步：实现登录接口（生成 JWT 令牌）​</span></a></h4><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code><span class="line"><span class="token keyword">func</span> <span class="token punctuation">(</span>s <span class="token operator">*</span>AdminService<span class="token punctuation">)</span> <span class="token function">Login</span><span class="token punctuation">(</span><span class="token boolean">_</span> context<span class="token punctuation">.</span>Context<span class="token punctuation">,</span> req <span class="token operator">*</span>v1<span class="token punctuation">.</span>LoginReq<span class="token punctuation">)</span> <span class="token punctuation">(</span><span class="token operator">*</span>v1<span class="token punctuation">.</span>User<span class="token punctuation">,</span> <span class="token builtin">error</span><span class="token punctuation">)</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token comment">// 1. 验证用户名密码（实际场景需查询数据库）</span></span>
<span class="line">    <span class="token keyword">if</span> req<span class="token punctuation">.</span>UserName <span class="token operator">==</span> <span class="token string">&quot;&quot;</span> <span class="token operator">||</span> req<span class="token punctuation">.</span>Password <span class="token operator">==</span> <span class="token string">&quot;&quot;</span> <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> errors<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;invalid username or password&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 2. 分配用户角色</span></span>
<span class="line">    <span class="token keyword">var</span> roles <span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token builtin">string</span></span>
<span class="line">    <span class="token keyword">switch</span> req<span class="token punctuation">.</span>UserName <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">case</span> <span class="token string">&quot;admin&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        roles <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>roles<span class="token punctuation">,</span> <span class="token string">&quot;ROLE_ADMIN&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">case</span> <span class="token string">&quot;moderator&quot;</span><span class="token punctuation">:</span></span>
<span class="line">        roles <span class="token operator">=</span> <span class="token function">append</span><span class="token punctuation">(</span>roles<span class="token punctuation">,</span> <span class="token string">&quot;ROLE_MODERATOR&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token keyword">default</span><span class="token punctuation">:</span></span>
<span class="line">        <span class="token keyword">return</span> <span class="token boolean">nil</span><span class="token punctuation">,</span> errors<span class="token punctuation">.</span><span class="token function">New</span><span class="token punctuation">(</span><span class="token string">&quot;user not found&quot;</span><span class="token punctuation">)</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 3. 生成JWT令牌</span></span>
<span class="line">    securityUser <span class="token operator">:=</span> <span class="token operator">&amp;</span>SecurityUser<span class="token punctuation">{</span>AuthorityId<span class="token punctuation">:</span> req<span class="token punctuation">.</span>UserName<span class="token punctuation">}</span></span>
<span class="line">    token <span class="token operator">:=</span> securityUser<span class="token punctuation">.</span><span class="token function">CreateAccessJwtToken</span><span class="token punctuation">(</span><span class="token punctuation">[</span><span class="token punctuation">]</span><span class="token function">byte</span><span class="token punctuation">(</span>s<span class="token punctuation">.</span>apiKey<span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line"></span>
<span class="line">    <span class="token comment">// 4. 返回用户信息与令牌</span></span>
<span class="line">    id <span class="token operator">:=</span> <span class="token function">uint64</span><span class="token punctuation">(</span><span class="token number">10</span><span class="token punctuation">)</span></span>
<span class="line">    email <span class="token operator">:=</span> <span class="token string">&quot;hello@kratos.com&quot;</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token operator">&amp;</span>v1<span class="token punctuation">.</span>User<span class="token punctuation">{</span></span>
<span class="line">        Id<span class="token punctuation">:</span>       <span class="token operator">&amp;</span>id<span class="token punctuation">,</span></span>
<span class="line">        UserName<span class="token punctuation">:</span> <span class="token operator">&amp;</span>req<span class="token punctuation">.</span>UserName<span class="token punctuation">,</span></span>
<span class="line">        Token<span class="token punctuation">:</span>    <span class="token operator">&amp;</span>token<span class="token punctuation">,</span></span>
<span class="line">        Email<span class="token punctuation">:</span>    <span class="token operator">&amp;</span>email<span class="token punctuation">,</span></span>
<span class="line">        Roles<span class="token punctuation">:</span>    roles<span class="token punctuation">,</span></span>
<span class="line">    <span class="token punctuation">}</span><span class="token punctuation">,</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="五、整体流程梳理​" tabindex="-1"><a class="header-anchor" href="#五、整体流程梳理​"><span>五、整体流程梳理​</span></a></h2><h3 id="_1-登录流程​" tabindex="-1"><a class="header-anchor" href="#_1-登录流程​"><span>1. 登录流程​</span></a></h3><p>前端提交用户名密码 → 登录接口验证身份 → 生成 JWT 令牌 → 返回给前端 → 前端存储令牌（localStorage）​</p><h3 id="_2-正常请求流程​" tabindex="-1"><a class="header-anchor" href="#_2-正常请求流程​"><span>2. 正常请求流程​</span></a></h3><ul><li>前端携带 JWT 令牌发起请求 → API 网关拦截请求​</li><li>JWT 中间件验证令牌有效性 → 解析用户信息存入上下文​</li><li>Casbin 中间件从上下文提取用户 / 资源 / 操作信息 → 校验权限​</li><li>权限通过 → 转发请求到业务服务；权限拒绝 → 返回 403 错误​</li></ul><h2 id="六、技术栈总结​" tabindex="-1"><a class="header-anchor" href="#六、技术栈总结​"><span>六、技术栈总结​</span></a></h2><table><thead><tr><th>技术组件</th><th>核心作用</th></tr></thead><tbody><tr><td><a href="https://go.dev/" target="_blank" rel="noopener noreferrer">Golang</a></td><td>后端开发语言</td></tr><tr><td><a href="https://reactjs.org/docs/getting-started.html" target="_blank" rel="noopener noreferrer">React</a></td><td>前端开发框架</td></tr><tr><td><a href="https://go-kratos.dev/" target="_blank" rel="noopener noreferrer">Kratos</a></td><td>微服务框架（提供中间件、服务治理能力）</td></tr><tr><td><a href="https://www.consul.io/" target="_blank" rel="noopener noreferrer">Consul</a></td><td>服务发现与配置中心</td></tr><tr><td><a href="https://www.jaegertracing.io/" target="_blank" rel="noopener noreferrer">Jaeger</a></td><td>分布式链路追踪</td></tr><tr><td><a href="https://jwt.io/" target="_blank" rel="noopener noreferrer">JWT</a></td><td>无状态身份认证令牌</td></tr><tr><td><a href="https://casbin.org/" target="_blank" rel="noopener noreferrer">Casbin</a></td><td>通用权限控制框架</td></tr></tbody></table><h2 id="七、开源示例代码" tabindex="-1"><a class="header-anchor" href="#七、开源示例代码"><span>七、开源示例代码</span></a></h2><ul><li>Casbin 中间件封装 <a href="https://github.com/tx7do/kratos-casbin" target="_blank" rel="noopener noreferrer">Kratos Casbin</a></li><li>权鉴中间件封装 <a href="https://github.com/tx7do/kratos-authz" target="_blank" rel="noopener noreferrer">Kratos Authz</a></li><li>完整示例项目 <a href="https://github.com/tx7do/kratos-examples/tree/main/casbin" target="_blank" rel="noopener noreferrer">Kratos Examples</a></li></ul>`,72)])])}const u=s(o,[["render",l]]),r=JSON.parse('{"path":"/posts/kratos_auth_authz.html","title":"Kratos微服务框架下的认证和鉴权","lang":"zh-CN","frontmatter":{"date":"2020-01-01T00:00:00.000Z","category":["Go编程"],"tag":["Golang","Go-Kratos"],"sticky":10},"headers":[{"level":2,"title":"一、认证与鉴权的核心区别​","slug":"一、认证与鉴权的核心区别​","link":"#一、认证与鉴权的核心区别​","children":[{"level":3,"title":"身份认证（Authentication）​","slug":"身份认证-authentication-​","link":"#身份认证-authentication-​","children":[]},{"level":3,"title":"授权（Authorization）​","slug":"授权-authorization-​","link":"#授权-authorization-​","children":[]}]},{"level":2,"title":"二、微服务下的认证与鉴权策略选型​","slug":"二、微服务下的认证与鉴权策略选型​","link":"#二、微服务下的认证与鉴权策略选型​","children":[]},{"level":2,"title":"三、有状态 vs 无状态身份验证​","slug":"三、有状态-vs-无状态身份验证​","link":"#三、有状态-vs-无状态身份验证​","children":[{"level":3,"title":"有状态认证（Cookie-Session 模式）​","slug":"有状态认证-cookie-session-模式-​","link":"#有状态认证-cookie-session-模式-​","children":[]},{"level":3,"title":"无状态认证（Token 模式）​","slug":"无状态认证-token-模式-​","link":"#无状态认证-token-模式-​","children":[]}]},{"level":2,"title":"四、技术实现方案​","slug":"四、技术实现方案​","link":"#四、技术实现方案​","children":[{"level":3,"title":"4.1 JWT：无状态认证的核心实现​","slug":"_4-1-jwt-无状态认证的核心实现​","link":"#_4-1-jwt-无状态认证的核心实现​","children":[]},{"level":3,"title":"4.2 Casbin：通用鉴权框架​","slug":"_4-2-casbin-通用鉴权框架​","link":"#_4-2-casbin-通用鉴权框架​","children":[]},{"level":3,"title":"4.3 Kratos 框架下的落地实现​","slug":"_4-3-kratos-框架下的落地实现​","link":"#_4-3-kratos-框架下的落地实现​","children":[]}]},{"level":2,"title":"五、整体流程梳理​","slug":"五、整体流程梳理​","link":"#五、整体流程梳理​","children":[{"level":3,"title":"1. 登录流程​","slug":"_1-登录流程​","link":"#_1-登录流程​","children":[]},{"level":3,"title":"2. 正常请求流程​","slug":"_2-正常请求流程​","link":"#_2-正常请求流程​","children":[]}]},{"level":2,"title":"六、技术栈总结​","slug":"六、技术栈总结​","link":"#六、技术栈总结​","children":[]},{"level":2,"title":"七、开源示例代码","slug":"七、开源示例代码","link":"#七、开源示例代码","children":[]}],"git":{"updatedTime":1774788457000,"contributors":[{"name":"tx7do","username":"tx7do","email":"yanglinbo@gmail.com","commits":7,"url":"https://github.com/tx7do"},{"name":"Bobo","username":"Bobo","email":"yanglinbo@gmail.com","commits":2,"url":"https://github.com/Bobo"}],"changelog":[{"hash":"a3e88b19cfead00baa606aa5110b2802dac32768","time":1774788457000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: REBUILD."},{"hash":"fd51de511b368394455459c4a4ee339bb857dad6","time":1763783146000,"email":"yanglinbo@gmail.com","author":"Bobo","message":"feat: edit post."},{"hash":"5ea33389b32f6034aec163973631e6723b20981a","time":1655867257000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post"},{"hash":"ca70090f61f5a208f4a721851d1527ce6f237677","time":1649054248000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post"},{"hash":"b317a457a67821ad4fc2c66aedacda59d9f36ef4","time":1648951986000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit post"},{"hash":"49ef2822ab763cd5b05a8f520e8e79c78fe0440c","time":1648883622000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit post"},{"hash":"52ac91c0d33666c1ea25c821237e1bab00bcc2c9","time":1648877056000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: edit post"},{"hash":"a158d4b85e2d3b8181c14949f8b50af4d691fa08","time":1648876884000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post"},{"hash":"0ea29738811f009bb1f39bf09bff25c5c51ffd8f","time":1648813110000,"email":"yanglinbo@gmail.com","author":"tx7do","message":"feat: add post"}]},"filePathRelative":"posts/kratos_auth_authz.md","excerpt":"\\n<p>从单体应用迁移到微服务架构，虽能收获松耦合、可扩展等诸多优势，但也引入了新的安全挑战。微服务通过开放 API 实现服务间通信，与单体应用相比：​</p>\\n<ul>\\n<li>攻击面显著扩大：每个独立服务都需单独保障安全性，风险点呈指数级增加​</li>\\n<li>通信安全性要求更高：API 调用不仅要验证身份，还需保障传输安全与可用性​</li>\\n</ul>\\n<p>因此，微服务架构需要一套与单体应用截然不同的安全解决方案，核心聚焦于认证（Authentication） 与鉴权（Authorization） 两大核心能力。</p>\\n<h2>一、认证与鉴权的核心区别​</h2>\\n<p><img src=\\"/assets/images/authn_vs_authz.jpg\\" alt=\\"认证和授权的区别\\"></p>"}');export{u as comp,r as data};
